1	//! Standalone `lua-rs` interpreter — minimal entry point that exercises the
2	//! full pipeline: `new_state` → `open_libs` → `load_string` → `pcall_k`.
3	//!
4	//! This is intentionally minimal — its job is to surface which `todo!()`
5	//! stubs block real execution, NOT to be a complete Lua interpreter.
6	//!
7	//! Usage:
8	//!   lua-rs '<lua source>'
9	//! Examples:
10	//!   lua-rs 'print("hello")'
11	//!   lua-rs '1+1'
12	
13	use std::io::{self, BufReader, BufWriter, Read, Seek, SeekFrom, Write};
14	use std::panic::{catch_unwind, AssertUnwindSafe};
15	use std::process::ExitCode;
16	
17	use lua_stdlib::auxlib::load_string;
18	use lua_stdlib::init::open_libs;
19	use lua_types::closure::LuaLClosure;
20	use lua_types::error::LuaError;
21	use lua_types::filehandle::LuaFileHandle;
22	use lua_types::gc::GcRef;
23	use lua_types::upval::UpVal;
24	use lua_types::value::LuaValue;
25	use lua_vm::api::{pcall_k, to_lua_string};
26	use lua_vm::state::{new_state, LuaState};
